        string memory name,
        string memory symbol,
        uint256 supply,
        uint8 decimals
    ) public ERC20(name, symbol) {
        _mint(msg.sender, supply);
        _setupDecimals(decimals);
    }

    function mintTokens(uint256 _amount) external {
        _mint(msg.sender, _amount);
    }
}

